<span class="token comment">//        \u89E3\u8BFB\uFF1A\u8FDE\u63A5\u672C\u673A\u76849999\u7AEF\u53E3  \u5982\u679C\u8FDE\u63A5\u6210\u529F\u4F1A\u8FD4\u56DE\u4E00\u4E2Asocket</span>
